\end{center}

\vspace{-0.3em}

\section*{SUMMARY}

MS Computer Science student (GPA: 4.11) at Arizona State University with 2+ years of production engineering experience designing backend services, data pipelines, and distributed systems. Proven track record of reducing latency by 40\%+ and automating workflows that saved hundreds of engineering hours. Skilled in Python, SQL, Kafka, Spark, Airflow, Docker, and Kubernetes, with hands-on exposure to LLM-integrated tooling and cloud-native data architectures.

\section*{EDUCATION}

\textbf{Arizona State University (GPA: 4.11/4.0)} \hfill Aug 2025 -- May 2027\\
Master of Science, Computer Science \hfill Tempe, AZ, USA

\vspace{0.1em}

\textbf{Maharaja Agrasen Institute of Technology (GPA: 3.7/4.0)} \hfill Aug 2019 -- Jul 2023\\
Bachelor of Science, Computer Science and Engineering \hfill New Delhi, India

\section*{SKILLS}

\textbf{Languages:} Python, JavaScript, TypeScript, Java, C++, SQL, Scala (familiar)\\
\textbf{Data Engineering:} Apache Spark (PySpark), Apache Airflow, Kafka, ETL/ELT pipelines, dbt (familiar), data modeling\\
\textbf{Backend \& APIs:} RESTful services, gRPC (familiar), OOP design, microservices, performance optimization\\
\textbf{Databases \& Storage:} PostgreSQL, MySQL, RocksDB, Neo4j, Snowflake (familiar), BigQuery (familiar)\\
\textbf{Cloud \& Infra:} AWS (S3, EC2, RDS, Lambda, EMR), Docker, Kubernetes, Linux, CI/CD (GitHub Actions, Jenkins)\\
\textbf{Frontend:} React, Next.js, Vue.js-style frameworks, HTML, CSS\\
\textbf{AI/ML:} LLM API integration, prompt engineering, Retrieval-Augmented Generation (RAG) pipelines (familiar)\\

\section*{EXPERIENCE}

\textbf{Software Engineer $|$ ZS Associates} \hfill Sep 2023 -- Jun 2025
\begin{itemize}
    \item Architected and owned 5+ production backend services in Python and Node.js backed by PostgreSQL, serving analytics workflows for 3+ cross-functional teams; reduced average API response latency by \textbf{40\%} through targeted SQL query optimization.
    \item Built and orchestrated \textbf{Airflow-managed ETL pipelines} that ingested, transformed, and delivered 10M+ daily records across internal data systems, reducing manual analyst intervention by \textbf{40\%} and cutting pipeline SLA violations from weekly to zero.
    \item Deployed \textbf{PySpark jobs on AWS EMR} to parallelize large-scale batch transformations, achieving a \textbf{3$\times$ throughput improvement} over single-node processing for a critical reporting dataset used by executive stakeholders.
    \item Delivered \textbf{3+ React dashboards} surfacing real-time KPIs (data freshness, pipeline health, SLA status) by integrating REST APIs with a PostgreSQL backend and caching layer, eliminating 6+ hours of weekly manual reporting.
    \item Introduced \textbf{CI/CD pipelines via GitHub Actions} for automated testing and deployment of backend services, reducing production deployment errors by \textbf{30\%} and cutting release cycle time from days to hours.
    \item Integrated an internal \textbf{LLM-based summarization tool} into the analytics reporting workflow using the OpenAI API, enabling automated natural-language summaries of KPI dashboards that saved analysts \textbf{3+ hours per sprint}.
    \item Modeled and maintained relational schemas in \textbf{PostgreSQL and Snowflake} supporting multi-tenant data delivery, enforcing referential integrity and implementing row-level access controls for 3+ product verticals.
\end{itemize}

\textbf{Software Engineer Intern $|$ Dreadnought School} \hfill Jun 2022 -- Aug 2022
\begin{itemize}
    \item Delivered 10+ backend feature modules using OOP design patterns within a Python/Node.js client--server architecture, achieving \textbf{zero critical bugs} in QA across all shipped modules.
    \item Designed and consumed REST APIs with schema-validated request/response cycles across PostgreSQL and MySQL, reducing data validation errors by \textbf{25\%} through centralized error-handling middleware.
    \item Accelerated team delivery by \textbf{20\%} by configuring a \textbf{CI/CD pipeline} (automated test runs + Docker-based staging deploys) for a 5+ engineer team, reducing integration conflicts on shared branches.
\end{itemize}

\textbf{Full-Stack Developer Intern $|$ Andwemet Pvt Ltd} \hfill Jun 2021 -- Oct 2021
\begin{itemize}
    \item Engineered a MERN-stack customer onboarding system from scratch that served 100+ active users, reducing onboarding completion time by \textbf{35\%} through iterative UX refinements and backend caching improvements.
    \item Built and documented \textbf{RESTful API endpoints} for user registration, validation, and onboarding-state management, increasing downstream feature adoption by \textbf{50\%} as measured via user interaction analytics.

\end{itemize}


\section*{PROJECTS}

\textbf{Real-Time Graph Analytics System $|$ Kafka, PySpark, RocksDB, Neo4j, Docker, Kubernetes, AWS S3}
\begin{itemize}
    \item Engineered a distributed event-streaming pipeline using \textbf{Kafka} for high-throughput ingestion and \textbf{PySpark} for parallel stream processing, achieving \textbf{2$\times$ throughput} under concurrent workloads across 4 containerized microservices.
    \item Persisted processed state in \textbf{RocksDB} and executed graph traversal algorithms in \textbf{Neo4j} to surface real-time relationship analytics; deployed the full stack on \textbf{Kubernetes (Minikube)} with auto-scaling policies, storing raw event logs in \textbf{AWS S3} for downstream replay.
\end{itemize}

\textbf{LLM-Powered Knowledge Assistant $|$ Python, OpenAI API, RAG, FastAPI, PostgreSQL (pgvector)}
\begin{itemize}
    \item Built a \textbf{Retrieval-Augmented Generation (RAG)} pipeline using OpenAI embeddings and \textbf{pgvector} to enable semantic search over a 10K+ document corpus, reducing average query-to-answer latency to under 2 seconds.
    \item Exposed the system as a \textbf{FastAPI} REST service with streaming responses, integrating prompt engineering techniques (chain-of-thought, few-shot) to improve answer relevance scores by \textbf{30\%} over a baseline keyword-search approach.
\end{itemize}

\end{document}

